package signaturekeys

import (
	"github.com/huaweicloud/golangsdk"
	"github.com/huaweicloud/golangsdk/pagination"
)

// SignOpts allows to create a new signature or update an existing environment using given parameters.
type SignOpts struct {
	// Signature key name, which can contain 3 to 64 characters, starting with a letter.
	// Only letters, digits, and underscores (_) are allowed.
	// Chinese characters must be in UTF-8 or Unicode format.
	SignName string `json:"name" required:"true"`
	// Signature key, which can contain 8 to 32 characters, starting with a letter.
	// Only letters, digits, hyphens (-), and underscores (_) are allowed.
	// A key is automatically generated by the backend if no key is specified.
	SignKey string `json:"sign_key,omitempty"`
	//Signature key type. Valid values are 'hmac' and 'basic'.
	SignType string `json:"sign_type,omitempty"`
	// Signature secret, which can contain 16 to 64 characters, starting with a letter.
	// Only letters, digits, and special characters (-_!@#$%) are allowed.
	// A secret is automatically generated by the backend if no secret is specified.
	SignSecret string `json:"sign_secret,omitempty"`
}

type SignOptsBuilder interface {
	ToSignOptsMap() (map[string]interface{}, error)
}

func (opts SignOpts) ToSignOptsMap() (map[string]interface{}, error) {
	return golangsdk.BuildRequestBody(opts, "")
}

// Create is a method by which to create function that create a new signature.
func Create(client *golangsdk.ServiceClient, instanceId string, opts SignOptsBuilder) (r CreateResult) {
	reqBody, err := opts.ToSignOptsMap()
	if err != nil {
		r.Err = err
		return
	}
	_, r.Err = client.Post(rootURL(client, instanceId), reqBody, &r.Body, nil)
	return
}

// Update is a method by which to udpate an existing environment.
func Update(client *golangsdk.ServiceClient, instanceId, signId string, opts SignOptsBuilder) (r UpdateResult) {
	reqBody, err := opts.ToSignOptsMap()
	if err != nil {
		r.Err = err
		return
	}
	_, r.Err = client.Put(resourceURL(client, instanceId, signId), reqBody, &r.Body, &golangsdk.RequestOpts{
		OkCodes: []int{200},
	})
	return
}

// ListOpts allows to filter list data using given parameters.
type ListOpts struct {
	// Signature key ID.
	Id string `q:"id"`
	// Signature name.
	Name string `q:"name"`
	// Offset from which the query starts.
	// If the offset is less than 0, the value is automatically converted to 0. Default to 0.
	Offset int `q:"offset"`
	// Number of items displayed on each page. The valid values are range form 1 to 500, default to 20.
	Limit int `q:"limit"`
	// Parameter name (name) for exact matching.
	PreciseSearch string `q:"precise_search"`
}

type ListOptsBuilder interface {
	ToListQuery() (string, error)
}

func (opts ListOpts) ToListQuery() (string, error) {
	q, err := golangsdk.BuildQueryString(opts)
	if err != nil {
		return "", err
	}
	return q.String(), err
}

// List is a method to obtain an array of one or more groups according to the query parameters.
func List(client *golangsdk.ServiceClient, instanceId string, opts ListOptsBuilder) pagination.Pager {
	url := rootURL(client, instanceId)
	if opts != nil {
		query, err := opts.ToListQuery()
		if err != nil {
			return pagination.Pager{Err: err}
		}
		url += query
	}

	return pagination.NewPager(client, url, func(r pagination.PageResult) pagination.Page {
		return SignatureKeyPage{pagination.SinglePageBase(r)}
	})
}

// Delete is a method to delete an existing signature key.
func Delete(client *golangsdk.ServiceClient, instanceId, signId string) (r DeleteResult) {
	_, r.Err = client.Delete(resourceURL(client, instanceId, signId), nil)
	return
}
